from outlines import prompt, register_filter, unregister_filter

register_filter('capitalize', str.upper)
unregister_filter('capitalize')

@prompt
def build(text):
    '''{{ text | capitalize }}'''

try:
    print(build('hello'))
    print('ERROR: should have raised')
except Exception as e:
    print('OK, raised as expected:', type(e).__name__)
